external_knowledge:
- 'Middle to upper-middle-class income bracket' refers to an annual income between 50001 and 100000; 
- 'Highly engaged' refers to customers with the highest engagement score among their overall engagements; 
- 'Been members for more than a year' means they have been members for more than 365 days.

sql:
SELECT transaction_amount
FROM customer_transactions
WHERE payment_method = 'PayPal';

SELECT AVG(engagement_score) AS average_engagement_score
FROM customer_engagement
WHERE customer_id = 0;
